import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    proj, tfm, pkg = k
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((proj, tfm, pkg, bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((proj, tfm, pkg, bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}): {c[2]}  {c[3]} -> {c[4]}')
else:
    print('  None')

print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}): {u[2]}  {u[3]}')
"

